import{_ as e,a as t,b as l,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as i,o as n,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Magnet Transfer","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/magnet-transfer.md","filePath":"ps/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"ps/Other/magnet-transfer.md"};function p(h,a,c,m,u,g){return n(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="magnet-transfer" tabindex="-1">Magnet Transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet Transfer&quot;">​</a></h1><p>Magnet transfer له magnet link څخه files download کوي او په اتومات ډول یې هغه cloud storage channel ته upload کوي چې تاسې ټاکلی وي.</p><p>دا د anime episodes، videos، archives او ورته files د transfer لپاره ګټور دی. magnet link paste کړئ، ImgBed background download task جوړوي. کله چې download بشپړ شي، file ImgBed ته upload کېږي او final link د upload list کې ښکاري.</p><p><img src="'+e+'" alt="Magnet transfer" loading="lazy"></p><h2 id="چېرته-یې-وکاروئ" tabindex="-1">چېرته یې وکاروئ <a class="header-anchor" href="#چېرته-یې-وکاروئ" aria-label="Permalink to &quot;چېرته یې وکاروئ&quot;">​</a></h2><p>د magnet transfer entry د homepage upload area کې دی.</p><p>magnet link input box ته paste کړئ، <code>Transfer</code> وټاکئ، بیا upload وکړئ.</p><p><img src="'+t+'" alt="Upload anime" loading="lazy"></p><h2 id="له-لومړي-استعمال-مخکې" tabindex="-1">له لومړي استعمال مخکې <a class="header-anchor" href="#له-لومړي-استعمال-مخکې" aria-label="Permalink to &quot;له لومړي استعمال مخکې&quot;">​</a></h2><p>لومړی په admin panel کې magnet transfer تنظیم کړئ.</p><p>عموما دې ته اړتیا لرئ:</p><ol><li>د download task چلولو لپاره GitHub account.</li><li>cloud upload channel، لکه Google Drive یا OneDrive.</li><li>target upload directory.</li><li>task timeout.</li></ol><p>کله چې settings تیار شول، homepage ته راشئ او د transfer پیل لپاره magnet link paste کړئ.</p><h2 id="magnet-link-upload-کول" tabindex="-1">Magnet Link Upload کول <a class="header-anchor" href="#magnet-link-upload-کول" aria-label="Permalink to &quot;Magnet Link Upload کول&quot;">​</a></h2><ol><li>magnet link د homepage upload box ته paste کړئ.</li><li>ډاډه شئ mode پر <code>Transfer</code> ټاکل شوی دی.</li><li>upload کلیک کړئ.</li><li>انتظار وکړئ چې ImgBed magnet task جوړ کړي.</li><li>کله چې task پیل شي، د progress کتلو لپاره په ښي ښکته کونج کې <code>Magnet Tasks</code> floating panel وکاروئ.</li></ol><p>Download او upload وخت نیولای شي. speed د magnet resource، GitHub runtime environment او ټاکل شوي cloud storage channel پورې تړلی دی.</p><p><img src="'+l+'" alt="Magnet downloading" loading="lazy"></p><h2 id="له-بشپړېدو-وروسته" tabindex="-1">له بشپړېدو وروسته <a class="header-anchor" href="#له-بشپړېدو-وروسته" aria-label="Permalink to &quot;له بشپړېدو وروسته&quot;">​</a></h2><p>کله چې task بشپړ شي، upload list د file name او link ښيي.</p><p>videos د video preview ښيي، images د image preview، او نور files عادي file icon ښيي.</p><p><img src="'+o+'" alt="Downloaded video" loading="lazy"></p><p>دا copy کولای شئ:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Use Case</th></tr></thead><tbody><tr><td>Original link</td><td>مستقیم file access</td></tr><tr><td>Markdown</td><td>Markdown posts یا notes</td></tr><tr><td>HTML</td><td>Web page code</td></tr><tr><td>BBCode</td><td>هغه forums چې BBCode ملاتړ کوي</td></tr></tbody></table><h2 id="magnet-task-panel" tabindex="-1">Magnet Task Panel <a class="header-anchor" href="#magnet-task-panel" aria-label="Permalink to &quot;Magnet Task Panel&quot;">​</a></h2><p>د ښي ښکته magnet task panel د task count، task name، progress او final status ښيي.</p><p>عام states:</p><table tabindex="0"><thead><tr><th>Status</th><th>معنا</th></tr></thead><tbody><tr><td>Waiting</td><td>task جوړ شوی او د چلولو انتظار کوي.</td></tr><tr><td>Downloading</td><td>magnet resource download کېږي.</td></tr><tr><td>Uploading</td><td>file download شوی او cloud storage ته upload کېږي.</td></tr><tr><td>Completed</td><td>upload بریالی دی او link copy کېدای شي.</td></tr><tr><td>Failed</td><td>task بریالی بشپړ نه شو. message وګورئ او بیا هڅه وکړئ.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>که magnet link څو files ولري، ImgBed د display لپاره اصلي completed file ته priority ورکوي.</li><li>لوی files ډېر وخت نیسي. د task تر بشپړېدو مخکې page refresh مه کوئ.</li><li>که magnet resource available peers ونه لري، ډېر slow یا fail کېدای شي.</li><li>که cloud account quota نه لري، authorization expire شوی وي، یا upload directory غلط وي، task fail کېدای شي.</li><li>Video preview د upload تر بشپړېدو وروسته څو ثانیې وخت نیولای شي.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="له-magnet-link-paste-وروسته-هېڅ-نه-پیلېږي" tabindex="-1">له Magnet Link Paste وروسته هېڅ نه پیلېږي <a class="header-anchor" href="#له-magnet-link-paste-وروسته-هېڅ-نه-پیلېږي" aria-label="Permalink to &quot;له Magnet Link Paste وروسته هېڅ نه پیلېږي&quot;">​</a></h3><p>ډاډه شئ magnet transfer په admin panel کې enabled دی او usable GitHub account او cloud channel ټاکل شوي دي.</p><h3 id="download-تل-slow-دی" tabindex="-1">Download تل Slow دی <a class="header-anchor" href="#download-تل-slow-دی" aria-label="Permalink to &quot;Download تل Slow دی&quot;">​</a></h3><p>Magnet speed پخپله resource پورې تړلی دی. که available peers نه وي، download ډېر slow یا ناشونی کېدای شي.</p><h3 id="له-upload-وروسته-preview-نه-ښکاري" tabindex="-1">له Upload وروسته Preview نه ښکاري <a class="header-anchor" href="#له-upload-وروسته-preview-نه-ښکاري" aria-label="Permalink to &quot;له Upload وروسته Preview نه ښکاري&quot;">​</a></h3><p>لومړی وګورئ file link پرانیستل کېږي. Video files ښايي په browser کې د load لپاره لږ وخت وغواړي، یا link مستقیم پرانیزئ.</p><h3 id="که-task-fail-شي-څه-وګورم؟" tabindex="-1">که Task Fail شي څه وګورم؟ <a class="header-anchor" href="#که-task-fail-شي-څه-وګورم؟" aria-label="Permalink to &quot;که Task Fail شي څه وګورم؟&quot;">​</a></h3><p>وګورئ magnet link valid دی، cloud channel کار کوي، او upload directory سمه ده. بیا task submit کړئ.</p>',38)])])}const w=i(s,[["render",p]]);export{b as __pageData,w as default};
